// e8-standard.mjs — the ATLAS-declared E₈ quantization standard, as a content-addressed UOR object.
// Every holospace-native LLM is compiled AGAINST this standard and references it by its did:holo. The
// standard is the shared, verifiable anchor: same lattice (E₈, generated by the atlas-12288 object),
// same incoherence policy, same adaptive rounding, same block format — so every compiled model is a
// self-verifying κ-object that re-derives against one declared standard. This is "anchored in ATLAS-
// declared E₈, 100% native to the UOR content-addressable substrate."
import { sha256hex } from "./atlas-probe.mjs";

const _enc = new TextEncoder();
const jcs = (v) => Array.isArray(v) ? "[" + v.map(jcs).join(",") + "]" : (v && typeof v === "object") ? "{" + Object.keys(v).sort().map((k) => JSON.stringify(k) + ":" + jcs(v[k])).join(",") + "}" : JSON.stringify(v);

// the κ of the native atlas-96 object that DECLARES the E₈ lattice (atlas → E₈ via the five foldings).
let _atlasK = null;
export async function atlasKappa(url = "./atlas12288.wasm") {
  if (_atlasK) return _atlasK;
  let bytes;
  if (typeof process !== "undefined" && process.versions?.node) { const { readFileSync } = await import("node:fs"); bytes = readFileSync(new URL(url, import.meta.url)); }
  else bytes = new Uint8Array(await (await fetch(url)).arrayBuffer());
  return (_atlasK = "did:holo:sha256:" + await sha256hex(bytes));
}

// the standard object (body, without its own id — that is its address).
export async function e8Standard({ bitRate = 2, atlasUrl } = {}) {
  const body = {
    "@context": ["https://www.w3.org/ns/did/v1", { schema: "https://schema.org/", prov: "http://www.w3.org/ns/prov#", hosc: "https://hologram.os/ns/conformance#", holo: "https://hologram.os/ns/q#" }],
    "@type": ["hosc:QuantizationStandard", "prov:Entity"],
    "schema:name": "ATLAS E₈ Quantization Standard",
    "schema:version": "e8std/1.0",
    "holo:lattice": "E8",
    "holo:latticeDeclaredBy": await atlasKappa(atlasUrl),     // the atlas object declares the lattice
    "holo:blockDim": 8,
    "holo:incoherence": "randomized-hadamard (deterministic seed)",
    "holo:adaptiveRounding": "LDLQ (input-Hessian, calibrated)",
    "holo:codebook": "E₈ lattice decode (Conway-Sloane) + entropy code",
    "holo:bitRate": bitRate,
    "holo:laws": ["L1 content-address", "L5 re-derivation"],
  };
  const id = "did:holo:sha256:" + await sha256hex(_enc.encode(jcs(body)));
  return { id, body };
}

// node: print the standard + its κ
if (typeof process !== "undefined" && process.argv[1] && process.argv[1].endsWith("e8-standard.mjs")) {
  const s = await e8Standard({ bitRate: 2 });
  console.log("ATLAS E₈ Quantization Standard");
  console.log("  declared-by (atlas):", s.body["holo:latticeDeclaredBy"]);
  console.log("  standard κ:", s.id);
  console.log("  body:", JSON.stringify(s.body, null, 2));
}
